+export function createPairingPrefixStripper(
+  prefixRe: RegExp,
+  map: (entry: string) => string = (entry) => entry,
+): NonNullable<ChannelPairingAdapter["normalizeAllowEntry"]> {
+  return (entry) => map(entry.replace(prefixRe, ""));
